### Pattern 3: `{ ok: true; ... } | { ok: false; error: string }` — inline discriminated unions (no shared type)

**Found in**: `/Users/jeevanpillay/Code/@lightfastai/lightfast/api/platform/src/lib/oauth/authorize.ts:45-47`
**Used for**: OAuth URL building

```ts
type AuthorizeResult =
  | { ok: true; url: string; state: string }
  | { ok: false; error: string };

export async function buildAuthorizeUrl(params): Promise<AuthorizeResult> {
  // ...
  return { ok: false, error: "unknown_provider" };
  return { ok: false, error: "invalid_redirect_to" };
  return { ok: true, url, state };
}
```

