1	/**
2	 * Platform service tRPC initialization.
3	 *
4	 * Auth model: service-to-service JWT (not Clerk).
5	 * All callers are internal services (app, platform, inngest, cron).
6	 */
7	import { initTRPC, TRPCError } from "@trpc/server";
8	import { parseError } from "@vendor/observability/error/next";
9	import { log } from "@vendor/observability/log/next";
10	import { createObservabilityMiddleware } from "@vendor/observability/trpc";
11	import superjson from "superjson";
12	import { ZodError } from "zod";
13	
14	import { verifyServiceJWT } from "./lib/jwt";
15	
16	// -- Auth Context -------------------------------------------------------------
17	
18	/**
19	 * Discriminated union for platform service authentication.
20	 * Every request resolves to exactly one variant.
21	 */
22	export type PlatformAuthContext =
23	  | { type: "service"; caller: string }
24	  | { type: "webhook"; provider: string }
25	  | { type: "inngest" }
26	  | { type: "cron" }
27	  | { type: "unauthenticated" };
28	
29	// -- Context Creation ---------------------------------------------------------
30	
31	/**
32	 * Create tRPC context for platform service requests.
33	 *
34	 * Auth resolution order:
35	 * 1. Bearer JWT in Authorization header -> service auth
36	 * 2. x-trpc-source header for internal identification
37	 * 3. Unauthenticated fallback
38	 */
39	export const createPlatformTRPCContext = async (opts: { headers: Headers }) => {
40	  const source = opts.headers.get("x-trpc-source") ?? "unknown";
41	
42	  // Check for service JWT in Authorization header
43	  const authHeader = opts.headers.get("authorization");
44	  if (authHeader?.startsWith("Bearer ")) {
45	    const token = authHeader.replace("Bearer ", "");
46	
47	    try {
48	      const verified = await verifyServiceJWT(token);
49	      log.info("[trpc] platform service request", {
50	        source,
51	        auth: "service",
52	        caller: verified.caller,
53	      });
54	      return {
55	        auth: {
56	          type: "service" as const,
57	          caller: verified.caller,
58	        },
59	        headers: opts.headers,
60	      };
61	    } catch (error) {
62	      log.warn("[trpc] JWT verification error", {
63	        source,
64	        error: parseError(error),
65	      });
66	    }
67	  }
68	
69	  // No authentication
70	  log.info("[trpc] platform service request", {
71	    source,
72	    auth: "unauthenticated",
73	  });
74	  return {
75	    auth: { type: "unauthenticated" as const },
76	    headers: opts.headers,
77	  };
78	};
79	
80	// -- tRPC Initialization ------------------------------------------------------
81	
82	const isProduction = process.env.NODE_ENV === "production";
83	
84	const t = initTRPC.context<typeof createPlatformTRPCContext>().create({
85	  transformer: superjson,
86	  errorFormatter: ({ shape, error }) => {
87	    const shouldSanitize =
88	      isProduction && error.code === "INTERNAL_SERVER_ERROR";
89	
90	    return {
91	      ...shape,
92	      message: shouldSanitize ? "An unexpected error occurred" : shape.message,
93	      data: {
94	        ...shape.data,
95	        zodError:
96	          error.cause instanceof ZodError ? error.cause.flatten() : null,
97	      },
98	    };
99	  },
100	});
101	
102	// -- Middleware ----------------------------------------------------------------
103	
104	const observabilityMiddleware = t.middleware(
105	  createObservabilityMiddleware({
106	    isDev: t._config.isDev,
107	    extractAuth: (ctx) => ({
108	      ...(ctx.auth.type === "service" && { caller: ctx.auth.caller }),
109	    }),
110	  })
111	);
112	
113	// -- Router & Procedure Exports -----------------------------------------------
114	
115	export const createTRPCRouter = t.router;
116	export const createCallerFactory = t.createCallerFactory;
117	
118	/**
119	 * Public procedure -- no auth required.
120	 * Use for health checks or publicly accessible endpoints.
121	 */
122	export const publicProcedure = t.procedure.use(observabilityMiddleware);
123	
124	/**
125	 * Service procedure -- requires valid service JWT.
126	 * Used by app or other internal services calling platform.
127	 *
128	 * Guarantees `ctx.auth.type === "service"` and `ctx.auth.caller` is available.
129	 */
130	export const serviceProcedure = t.procedure
131	  .use(observabilityMiddleware)
132	  .use(({ ctx, next }) => {
133	    if (ctx.auth.type !== "service") {
134	      throw new TRPCError({
